{"content": "     1|import { createClient } from '@/lib/supabase/server';
     2|import { ProductForm } from '@/components/admin/product-form';
     3|import { notFound } from 'next/navigation';
     4|
     5|interface Props {
     6|  params: Promise<{ id: string }>;
     7|}
     8|
     9|export default async function ProductoEditPage({ params }: Props) {
    10|  const { id } = await params;
    11|  const supabase = await createClient();
    12|  const isNew = id === 'nuevo';
    13|
    14|  // Fetch categories for the form
    15|  const { data: categoriesData } = await supabase
    16|    .from('categories')
    17|    .select('*')
    18|    .order('name');
    19|
    20|  const categories = ((categoriesData as any[]) || [])
    21|    .filter((c) => c.is_active)
    22|    .map((c) => ({ id: c.id, name: c.name }));
    23|
    24|  let product = null;
    25|
    26|  if (!isNew) {
    27|    const { data, error } = await supabase
    28|      .from('products')
    29|      .select('*')
    30|      .eq('id', id)
    31|      .single();
    32|
    33|    if (error || !data) {
    34|      notFound();
    35|    }
    36|    product = data as any;
    37|  }
    38|
    39|  return (
    40|    <div className="space-y-6">
    41|      <div>
    42|        <h2 className="text-3xl font-bold tracking-tight">
    43|          {isNew ? 'Nuevo Producto' : 'Editar Producto'}
    44|        </h2>
    45|        <p className="text-muted-foreground">
    46|          {isNew
    47|            ? 'Agrega un nuevo producto al catálogo'
    48|            : `Editando: ${product?.name}`}
    49|        </p>
    50|      </div>
    51|
    52|      <ProductForm
    53|        product={product}
    54|        categories={categories || []}
    55|        isNew={isNew}
    56|      />
    57|    </div>
    58|  );
    59|}
