     2|
     3|import { useState } from 'react';
     4|import { useRouter } from 'next/navigation';
     5|import { createClient } from '@/lib/supabase/client';
     6|import { Button } from '@/components/ui/button';
     7|import { Save } from 'lucide-react';
     8|
     9|const statuses = [
    10|  { value: 'pending', label: 'Pendiente' },
    11|  { value: 'confirmed', label: 'Confirmado' },
    12|  { value: 'preparing', label: 'Preparando' },
    13|  { value: 'shipped', label: 'Enviado' },
    14|  { value: 'delivered', label: 'Entregado' },
    15|  { value: 'cancelled', label: 'Cancelado' },
    16|];
    17|
    18|export function OrderStatusUpdate({
    19|  orderId,
    20|  currentStatus,
    21|}: {
    22|  orderId: string;
    23|  currentStatus: string;
    24|}) {
    25|  const router = useRouter();
    26|  const supabase = createClient();
    27|  const [status, setStatus] = useState(currentStatus);
    28|  const [loading, setLoading] = useState(false);
    29|  const [message, setMessage] = useState<string | null>(null);
    30|
    31|  const handleUpdate = async () => {
    32|    if (status === currentStatus) return;
    33|
    34|    setLoading(true);
    35|    setMessage(null);
    36|
    37|    try {
    38|      const { error } = await (supabase
    39|        .from('orders') as any)
    40|        .update({ status })
    41|        .eq('id', orderId);
    42|
    43|      if (error) throw error;
    44|
    45|      setMessage('Estado actualizado correctamente');
    46|      router.refresh();
    47|    } catch (err: any) {
    48|      setMessage(`Error: ${err.message}`);
    49|    } finally {
    50|      setLoading(false);
    51|    }
    52|  };
    53|
    54|  return (
    55|    <div className="space-y-3">
    56|      <select
    57|        value={status}
    58|        onChange={(e) => setStatus(e.target.value)}
    59|        className="flex h-9 w-full rounded-lg border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
    60|      >
    61|        {statuses.map((s) => (
    62|          <option key={s.value} value={s.value}>
    63|            {s.label}
    64|          </option>
    65|        ))}
    66|      </select>
    67|
    68|      <Button
    69|        onClick={handleUpdate}
    70|        disabled={loading || status === currentStatus}
    71|        className="w-full"
    72|        size="sm"
    73|      >
    74|        <Save className="h-4 w-4 mr-1" />
    75|        {loading ? 'Actualizando...' : 'Actualizar Estado'}
    76|      </Button>
    77|
    78|      {message && (
    79|        <p
    80|          className={`text-xs ${
    81|            message.startsWith('Error')
    82|              ? 'text-red-600'
    83|              : 'text-green-600'
    84|          }`}
    85|        >
    86|          {message}
    87|        </p>
    88|      )}
    89|    </div>
    90|  );
    91|}
